@Test
    void calculateDiffAngleTest() {
        Point diff = Localizer.calculateMovement((8.5 - 4.4) * (-Math.PI / 3), 4.4 * (Math.PI / 3), 8.5, Math.PI * 2 / 3);
        assertEquals(diff.getX(), (4.4 - (8.5 / 2)) * 1, EPSILON);
        assertEquals(diff.getY(), (4.4 - (8.5 / 2)) * 0, EPSILON);
    }

